// tsconfig.json
{
  "compilerOptions": {
    "experimentalDecorators": true,  // enable legacy decorator syntax
    "emitDecoratorMetadata": true    // emit design:type / design:paramtypes / design:returntype
  }
}

// main.ts (Angular adds this automatically)
import 'reflect-metadata';
import { bootstrapApplication } from '@angular/platform-browser';
import { AppComponent } from './app/app.component';

bootstrapApplication(AppComponent);

const PERMISSION_KEY = Symbol('permissions');

function Permissions(...roles: string[]) {
  return (target: Function): void => {
    Reflect.defineMetadata(PERMISSION_KEY, roles, target);
  };
}

function getPermissions(target: Function): string[] {
  return Reflect.getMetadata(PERMISSION_KEY, target) ?? [];
}

@Permissions('admin', 'editor')
class ReportPage {}

console.log(getPermissions(ReportPage)); // ['admin', 'editor']

import 'reflect-metadata';

@Injectable()
class UserService {
  constructor(private http: HttpClient, private router: Router) {}
}

// What the compiler emits (simplified):
Reflect.defineMetadata(
  'design:paramtypes',
  [HttpClient, Router],    // Angular reads this to know what to inject
  UserService
);

// Read it yourself:
const paramTypes = Reflect.getMetadata('design:paramtypes', UserService);
console.log(paramTypes); // [Function: HttpClient, Function: Router]

const TAG_KEY = Symbol('tag');

function Tag(value: string) {
  return (target: Function) => {
    Reflect.defineMetadata(TAG_KEY, value, target);
  };
}

@Tag('base')
class Base {}

class Child extends Base {}

// getMetadata walks the chain
console.log(Reflect.getMetadata(TAG_KEY, Child));    // 'base' — found on Base
console.log(Reflect.getOwnMetadata(TAG_KEY, Child)); // undefined — not on Child itself

// Override in Child
@Tag('child-override')
class Child2 extends Base {}
console.log(Reflect.getMetadata(TAG_KEY, Child2));   // 'child-override'

// Simplified version of what Angular's @Injectable does under the hood:
function Injectable(options?: { providedIn?: string }) {
  return (target: Function): void => {
    // Read the constructor parameter types emitted by tsc
    const paramTypes: Function[] = Reflect.getMetadata('design:paramtypes', target) ?? [];

    // Store them so the injector can use them at construction time
    Reflect.defineMetadata('__injectable__', { paramTypes, options }, target);
  };
}

// A practical pattern: read metadata in a guard to allow/deny access
const ROLES_KEY = Symbol('roles');

function Roles(...roles: string[]) {
  return (target: Function) => Reflect.defineMetadata(ROLES_KEY, roles, target);
}

@Injectable({ providedIn: 'root' })
class RolesGuard implements CanActivate {
  constructor(private auth: AuthService) {}

  canActivate(route: ActivatedRouteSnapshot): boolean {
    const component = route.component as Function | null;
    if (!component) return true;
    const required: string[] = Reflect.getMetadata(ROLES_KEY, component) ?? [];
    if (!required.length) return true;
    return required.some(r => this.auth.hasRole(r));
  }
}

@Roles('admin')
@Component({ selector: 'app-admin', template: '...', standalone: true })
export class AdminComponent {}

import 'reflect-metadata';

const registry = new Map<Function, unknown>();

// Mark a class as injectable and register it
function Injectable(target: Function): void {
  // Angular reads design:paramtypes — TypeScript emits this automatically
  const paramTypes: Function[] = Reflect.getMetadata('design:paramtypes', target) ?? [];
  registry.set(target, null); // sentinel — not yet instantiated
  Reflect.defineMetadata('paramTypes', paramTypes, target);
}

// Recursively resolve and instantiate a class
function resolve<T>(token: new (...args: unknown[]) => T): T {
  if (!registry.has(token)) {
    throw new Error(\`No provider for \${token.name}\`);
  }

  const existing = registry.get(token);
  if (existing) return existing as T;

  const paramTypes: Function[] = Reflect.getMetadata('paramTypes', token) ?? [];
  const deps = paramTypes.map(dep => resolve(dep as new (...args: unknown[]) => unknown));

  const instance = new token(...deps);
  registry.set(token, instance);
  return instance;
}

// Usage:
@Injectable
class LoggerService {
  log(msg: string): void { console.log(msg); }
}

@Injectable
class UserService {
  // TypeScript emits design:paramtypes = [LoggerService] for this constructor
  constructor(private logger: LoggerService) {}

  getUser(id: string): void { this.logger.log(\`Getting user \${id}\`); }
}

const userSvc = resolve(UserService);
userSvc.getUser('u1'); // 'Getting user u1'

const COLUMN_META = Symbol('column');
const TABLE_META  = Symbol('table');

interface ColumnOptions { name?: string; type: 'text' | 'int' | 'boolean'; }

function Entity(tableName: string) {
  return (target: Function) => Reflect.defineMetadata(TABLE_META, tableName, target);
}

function Column(options: ColumnOptions) {
  return (target: object, key: string) => {
    const cols: Map<string, ColumnOptions> =
      Reflect.getMetadata(COLUMN_META, target) ?? new Map();
    cols.set(key, options);
    Reflect.defineMetadata(COLUMN_META, cols, target);
  };
}

@Entity('users')
class User {
  @Column({ name: 'user_id', type: 'text' }) id = '';
  @Column({ type: 'text' }) name = '';
  @Column({ type: 'boolean' }) isActive = true;
}

// Introspect at runtime:
const table: string = Reflect.getMetadata(TABLE_META, User);
const cols: Map<string, ColumnOptions> = Reflect.getMetadata(COLUMN_META, User.prototype);

console.log(table);               // 'users'
cols.forEach((opts, field) => {
  const colName = opts.name ?? field;
  console.log(\`\${field} → \${colName} (\${opts.type})\`);
});
// id     → user_id (text)
// name   → name (text)
// isActive → isActive (boolean)

function Prop(target: object, key: string): void {
  const type = Reflect.getMetadata('design:type', target, key);
  console.log(\`\${key}: design:type = \${type?.name}\`);
}

class Form {
  @Prop name: string = '';       // design:type = String
  @Prop age: number = 0;         // design:type = Number
  @Prop active: boolean = false; // design:type = Boolean
}

// Output at class definition time:
// name: design:type = String
// age:  design:type = Number
// active: design:type = Boolean

// Limitation: interface types, union types, and generics all emit Object
// because they have no runtime constructor function

const API_META = Symbol('api');

interface ApiOptions { method: 'GET' | 'POST' | 'PUT' | 'DELETE'; path: string; }

function ApiRoute(options: ApiOptions) {
  return (target: object, key: string, descriptor: PropertyDescriptor) => {
    Reflect.defineMetadata(API_META, options, target, key);
    return descriptor;
  };
}

function getRoutes(controller: object): Array<{ method: string; path: string; handler: string }> {
  return Object.getOwnPropertyNames(Object.getPrototypeOf(controller))
    .filter(key => key !== 'constructor')
    .flatMap(key => {
      const meta: ApiOptions | undefined = Reflect.getMetadata(API_META, controller, key);
      return meta ? [{ method: meta.method, path: meta.path, handler: key }] : [];
    });
}

class UserController {
  @ApiRoute({ method: 'GET', path: '/users' })
  listUsers() {}

  @ApiRoute({ method: 'POST', path: '/users' })
  createUser() {}

  @ApiRoute({ method: 'GET', path: '/users/:id' })
  getUser() {}
}

const ctrl = new UserController();
console.log(getRoutes(ctrl));
// [{ method: 'GET', path: '/users', handler: 'listUsers' }, ...]

describe('Metadata decorators', () => {
  describe('@Column', () => {
    it('records column name and type', () => {
      const cols: Map<string, ColumnOptions> = Reflect.getMetadata(COLUMN_META, User.prototype);
      expect(cols.get('id')).toEqual({ name: 'user_id', type: 'text' });
      expect(cols.get('name')).toEqual({ type: 'text' });
    });
  });

  describe('@Entity', () => {
    it('records the table name on the class', () => {
      expect(Reflect.getMetadata(TABLE_META, User)).toBe('users');
    });
  });

  describe('@ApiRoute', () => {
    it('stores method and path metadata on the controller prototype', () => {
      const meta: ApiOptions = Reflect.getMetadata(API_META, UserController.prototype, 'listUsers');
      expect(meta.method).toBe('GET');
      expect(meta.path).toBe('/users');
    });
  });

  describe('design:paramtypes', () => {
    it('emits constructor parameter types', () => {
      @Injectable
      class Svc { constructor(private logger: LoggerService) {} }
      const types: Function[] = Reflect.getMetadata('design:paramtypes', Svc);
      expect(types[0]).toBe(LoggerService);
    });
  });
});
